62	// ---- macros are dropped ---------------------------------------------------
63	
64	#[test]
65	fn drops_macro_declarations() {
66	    let x = var("x", SortHint::Untagged);
67	    let t = theory(vec![
68	        TheoryItem::Macros(vec![mdef("m", &[x.clone()], msg("x"))]),
69	        TheoryItem::Rule(rule_act("R", vec![fact("In", vec![msg("x")])],
70	                                  fact("Act", vec![app("m", vec![msg("x")])]))),
71	    ]);
72	    let out = expand(&t);
73	    assert!(!out.items.iter().any(|it| matches!(it, TheoryItem::Macros(_))),
74	            "macros: declarations must be removed");
75	    assert_eq!(out.items.len(), 1);
76	}
