78	// ---- Q7: simultaneous (capture-avoiding) substitution ---------------------
79	
80	#[test]
81	fn capture_simultaneous_substitution() {
82	    // swap(x,y) = <x,y>;  Act(swap(y,x))  ==>  Act(<y,x>)
83	    let (x, y) = (var("x", SortHint::Untagged), var("y", SortHint::Untagged));
84	    let t = theory(vec![
85	        TheoryItem::Macros(vec![mdef("swap", &[x.clone(), y.clone()],
86	                                     pair(vec![msg("x"), msg("y")]))]),
87	        TheoryItem::Rule(rule_act(
88	            "R",
89	            vec![fact("In", vec![msg("x")]), fact("In", vec![msg("y")])],
90	            fact("Act", vec![app("swap", vec![msg("y"), msg("x")])]),
91	        )),
92	    ]);
93	    assert_eq!(only_rule_action_arg(&expand(&t)), pair(vec![msg("y"), msg("x")]));
94	    // A sequential (buggy) substitution would give <x,x> or <y,y>.
95	    assert_ne!(only_rule_action_arg(&expand(&t)), pair(vec![msg("x"), msg("x")]));
96	    assert_ne!(only_rule_action_arg(&expand(&t)), pair(vec![msg("y"), msg("y")]));
97	}
